+    /// Convert BF16 to Float32
+    /// BF16 format: sign(1) | exponent(8) | mantissa(7)
+    /// Float32 format: sign(1) | exponent(8) | mantissa(23)
+    /// Conversion: Just shift left by 16 bits (add 16 zero bits to mantissa)
+    fn bf16ToFloat32(bf16_val: BF16) f32 {
+        const bits: u32 = @as(u32, bf16_val) << 16;
+        return @bitCast(bits);
+    }
+
+    /// Convert Float32 to BF16 (with rounding)
+    fn float32ToBF16(f32_val: f32) BF16 {
+        const bits: u32 = @bitCast(f32_val);
+        // Round to nearest even (RNE)
+        const rounding_bias: u32 = 0x00007FFF + ((bits >> 16) & 1);
+        const rounded = bits + rounding_bias;
+        return @truncate(rounded >> 16);
+    }
